previewCss:
.darma-loader-darma-custom-475 {color: var(--loader-color, #b45309);
  --loader-secondary-color: #fcd34d;
  --loader-bg: #ffffff;
   width: 80px;
   height: 40px;
   background: var(--loader-color, #b45309);
   position: relative;
   overflow: hidden;
}
.darma-loader-darma-custom-475:before  {
  content: "";
   position: absolute;
   top: 10px;
   left: 0;
   height: 20px;
   width: 30px;
   background: radial-gradient(farthest-side,currentColor 50%,currentColor 52% 80%,#0000) 78% 22%/5px 5px, radial-gradient(farthest-side, var(--loader-secondary-color, #fcd34d) 92%,#0000) right/80% 100%, radial-gradient(farthest-side at left,var(--loader-secondary-color, #fcd34d) 92%,#0000) left/35% 80%;
   background-repeat: no-repeat;
   clip-path: polygon(0 0,100% 0,100% 40%,81% 50%,100% 60%,100% 100%,0 100%,20% 50%);
   animation: darma-loader-darma-custom-475-l15 1.5s infinite;
}
@keyframes darma-loader-darma-custom-475-l15  {
  0% {transform: translate(-100%)}
40% {transform: translate(15px)}
80%, 100% {transform: translate(100px)}
}

